(function() {
  const oldContainer = document.getElementById('thomson-particles');
  if (oldContainer) oldContainer.remove();

  const container = document.createElement('div');
  container.id = 'thomson-particles';
  container.style.cssText = `
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    z-index: 0;
    overflow: hidden;
  `;
  document.body.prepend(container);

  const count = 250;
  const colors = [
    'rgba(160,160,255,0.6)',
    'rgba(200,200,255,0.4)',
    'rgba(120,120,200,0.3)',
    'rgba(255,255,255,0.3)',
    'rgba(180,140,255,0.4)'
  ];

  for (let i = 0; i < count; i++) {
    const star = document.createElement('div');
    const size = Math.random() * 4 + 1.5;
    const x = Math.random() * 100;
    const y = Math.random() * 100;
    const duration = Math.random() * 25 + 15;
    const delay = Math.random() * 30;
    const color = colors[Math.floor(Math.random() * colors.length)];
    const opacity = Math.random() * 0.5 + 0.3;

    star.style.cssText = `
      position: absolute;
      left: ${x}%;
      top: ${y}%;
      width: ${size}px;
      height: ${size}px;
      background: ${color};
      border-radius: 50%;
      box-shadow: 0 0 ${size * 2}px ${color};
      animation: floatStar ${duration}s linear infinite, twinkleStar ${Math.random()*4+2}s ease-in-out ${Math.random()*5}s infinite alternate;
      animation-delay: ${delay}s, ${Math.random()*5}s;
      will-change: transform, opacity;
      opacity: ${opacity};
    `;
    container.appendChild(star);
  }

  if (!document.getElementById('thomson-star-styles')) {
    const style = document.createElement('style');
    style.id = 'thomson-star-styles';
    style.textContent = `
      @keyframes floatStar {
        0% { transform: translate(0, 0) scale(1) rotate(0deg); }
        25% { transform: translate(40px, -60px) scale(1.3) rotate(90deg); }
        50% { transform: translate(-30px, 40px) scale(0.8) rotate(180deg); }
        75% { transform: translate(50px, 30px) scale(1.1) rotate(270deg); }
        100% { transform: translate(-40px, -50px) scale(1) rotate(360deg); }
      }
      @keyframes twinkleStar {
        0% { opacity: 0.2; }
        100% { opacity: 1; }
      }
    `;
    document.head.appendChild(style);
  }
})();
